/**
 * QuoteBuilder -> stargtm /generate
 * Does NOT recalculate finance - UI Quote Sheet is the source of truth.
 * Finance values are passed through, never invented.
 */
const raw = $json.body || $json;
const lead = raw.nexusLead || raw.lead || {};
const fin = raw.financials || {};
const form = raw.form || raw;

const upgradeIdMap = {
  'Live DJ': 'live_dj', Saxophonist: 'saxophonist', Karaoke: 'karaoke',
  'Photo Booth': 'photo_booth', 'Close-up Magician': 'close_up_magician',
  'Close up Magician': 'close_up_magician', 'Branded Vessel Flag': 'branded_vessel_flag',
  'Acoustic Artist': 'acoustic_artist', 'Jazz and Sax Duo': 'jazz_sax_duo',
  'Additional Hour on Board': 'extra_hour', 'Casino Table with Croupier': 'casino_table',
  'Social Media Highlight Reel': 'social_highlight_reel', 'Mingling Tour Guide': 'mingling_guide',
  'Bespoke Logo Bunting': 'logo_bunting', 'Unlimited Drinks (4 hrs)': 'unlimited_drinks',
  'Unlimited Drinks': 'unlimited_drinks', 'Drink Tokens': 'drink_tokens',
  'Street Food Upgrade': 'street_food_upgrade',
};

function addIfPresent(obj, key, value) {
  if (value !== undefined && value !== null && String(value).trim() !== '') obj[key] = String(value);
}
function money(n) {
  const v = Number(n);
  if (!Number.isFinite(v)) return 0;
  return Math.round((v + Number.EPSILON) * 100) / 100;
}
function mapUpgrades(selected) {
  return (Array.isArray(selected) ? selected : [])
    .map((u) => {
      if (typeof u !== 'string') return null;
      if (upgradeIdMap[u]) return upgradeIdMap[u];
      if (u.includes('_')) return u;
      return null;
    })
    .filter(Boolean);
}

const prebuilt = raw.calculations || {};
const packageCost = money(prebuilt.package_cost ?? fin.costToClient ?? fin.package_cost ?? 0);
const vat = money(prebuilt.vat ?? fin.vat ?? 0);
const grandTotal = money(prebuilt.grand_total ?? fin.grandTotal ?? fin.grand ?? (packageCost + vat));
const guests = Number(prebuilt.guests ?? form.guestCount ?? raw.guestCount) || 0;
const eventType = form.eventType || raw.eventType || raw.event_type || lead.eventType || lead.event_type || '';
const selected = raw.selectedUpgradeLabels || form.selectedUpgrades || raw.selectedUpgrades || [];
const selectedInserts = Array.isArray(raw.selectedInserts) ? raw.selectedInserts
  : (Array.isArray(form.selectedInserts) ? form.selectedInserts : []);
const templateId = raw.template_id || form.templateId || raw.templateId || '';

const leadOut = {
  proposal_ref: lead.referenceNumber || lead.proposal_ref || (raw.lead && raw.lead.proposal_ref) || ('WE.' + Math.floor(1000 + Math.random() * 9000)),
  quote_date: new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' }) + ' | Quotation valid for 28 days',
};
addIfPresent(leadOut, 'client_name', lead.name || lead.client_name);
addIfPresent(leadOut, 'organisation', lead.companyName || lead.company || lead.organisation);
addIfPresent(leadOut, 'telephone', lead.phone || lead.telephone);
addIfPresent(leadOut, 'email', lead.email);
addIfPresent(leadOut, 'event_type', eventType);

// Flexible date -> "Date TBC"
const flexibleFlag = lead.eventDateFlexibleBool === true || /(tbc|flexible|yes)/i.test(String(lead.eventDateFlexible || ''));
const eventDateVal = form.eventDate || raw.eventDate || lead.eventDateDisplay || lead.fullEventDate;
if (flexibleFlag) { leadOut.event_date = 'Date TBC'; } else { addIfPresent(leadOut, 'event_date', eventDateVal); }

const embark = form.embarkation || raw.embarkation;
const disembark = form.disembarkation || raw.disembarkation;
if (embark || disembark) { leadOut.event_timings = (embark || '') + ' - ' + (disembark || ''); }
if (!leadOut.event_timings) addIfPresent(leadOut, 'event_timings', lead.requestedEventTimes);

addIfPresent(leadOut, 'guest_range', form.guestCount || raw.guestCount || lead.groupSize);
addIfPresent(leadOut, 'guest_quote_n', String(guests || lead.groupSizeQuote || form.guestCount || raw.guestCount || ''));

// New business fields passed through cleanly
addIfPresent(leadOut, 'budget', lead.budget || raw.budget || form.budget);
addIfPresent(leadOut, 'vessels', lead.vessels || raw.vessels || form.vessels);
addIfPresent(leadOut, 'market', lead.market || raw.market);
addIfPresent(leadOut, 'source', lead.source || raw.source);
addIfPresent(leadOut, 'year_of_event', lead.yearOfEvent || raw.yearOfEvent);
const repeatVal = lead.repeatClient ?? raw.repeatClient ?? form.repeatClient;
addIfPresent(leadOut, 'repeat_client', typeof repeatVal === 'boolean' ? (repeatVal ? 'YES' : 'NO') : repeatVal);
addIfPresent(leadOut, 'agent', lead.agent || raw.agent || form.agent); // UI-supplied only; no Enquiry column

// Staff / contact defaults (staff insert overrides Katherine)
leadOut.contact_name = lead.contact_name || 'Katherine Bulaon';
leadOut.contact_title = lead.contact_title || 'Client Relationship Manager';
leadOut.contact_phone = lead.contact_phone || '020 8323 5827';
leadOut.contact_email = lead.contact_email || 'sales@westendonthethames.com';
// prepared_by = the lead's REP (Client Relationship Representative), fallback to contact
addIfPresent(leadOut, 'prepared_by', lead.preparedBy || lead.assignedRep || lead.prepared_by || leadOut.contact_name);

const lower = String(eventType).toLowerCase();
const category = raw.category || form.proposalCategory ||
  (lower.includes('wedding') || lower.includes('engagement') ? 'wedding' : (eventType ? 'corporate' : undefined));

const mapped = mapUpgrades(selected);
const out = {
  event_type: eventType,
  ...(category ? { category } : {}),
  ...(templateId ? { template_id: templateId, manual_template: true } : {}),
  lead: leadOut,
  calculations: { guests, package_cost: packageCost, vat, grand_total: grandTotal },
  selectedUpgrades: mapped.length ? mapped : (Array.isArray(raw.selectedUpgrades) ? raw.selectedUpgrades.filter((u) => typeof u === 'string' && u.includes('_')) : []),
  selectedInserts,
  packageWording: raw.packageWording || {},
  menuLinks: raw.menuLinks || form.menuLinks || {},
  mode: raw.mode === 'live' ? 'live' : 'demo',
};
return [{ json: out }];

const body = $json.body || $json;
const mode = body.mode === 'live' ? 'live' : 'demo';
return [{ json: { mode, _fetch: true } }];

// Flexible header matching -> full Sapphire alias set. No presumption of exact headers.
const mode = ($('Lead Fetch Mode1').first().json.mode) === 'live' ? 'live' : 'demo';

const wanted = [
  ['Client Reference Number', 'referenceNumber'],
  ['Name', 'name'],
  ['Company Name', 'companyName'],
  ['Company Sector', 'companySector'],
  ['Main Contact - Email', 'email'],
  ['Main Contact - Number', 'phone'],
  ['Main Contact - Job Role', 'jobRole'],
  ['Budget', 'budget'],
  ['Repeat Client', 'repeatClient'],
  ['Client Relationship Representative', 'preparedBy'],
  ['Status', 'status'],
  ['Live/Dead', 'liveDead'],
  ['Source', 'source'],
  ['Enquiry Date', 'enquiryDate'],
  ['Event Type', 'eventType'],
  ['Full Event Date', 'fullEventDate'],
  ['Event Date - Flexible', 'eventDateFlexible'],
  ['Requested Event Times', 'requestedEventTimes'],
  ['Group Size', 'groupSize'],
  ['What vessel', 'vessels'],
  ['Market', 'market'],
  ['Best time to call', 'bestTimeToCall'],
  ['Year of Event', 'yearOfEvent'],
];

function norm(s) { return String(s).replace(/\s+/g, ' ').trim().toLowerCase(); }
function pick(row, prefix) {
  const target = norm(prefix);
  for (const key of Object.keys(row)) {
    if (norm(key).startsWith(target)) {
      const v = row[key];
      if (v !== undefined && v !== null && String(v).trim() !== '') return row[key];
    }
  }
  return '';
}
function lowerBound(g) {
  const m = String(g).match(/\d+/);
  return m ? Number(m[0]) : '';
}
function collectProgress(row) {
  const entries = [];
  for (const key of Object.keys(row)) {
    const mm = norm(key).match(/^progress\s+(\d+)$/);
    if (mm) {
      const v = row[key];
      if (v !== undefined && v !== null && String(v).trim() !== '') entries.push([Number(mm[1]), String(row[key]).trim()]);
    }
  }
  entries.sort((a, b) => a[0] - b[0]);
  return entries.map((e) => e[1]).join(' | ');
}
function isFlexible(v) {
  const s = norm(v);
  return s.includes('yes') || s.includes('tbc') || s.includes('flex');
}

const leads = $input.all().map((item) => {
  const row = item.json || {};
  const out = {};
  for (const [prefix, alias] of wanted) out[alias] = pick(row, prefix);
  // derived
  out.assignedRep = out.preparedBy;
  out.groupSizeQuote = lowerBound(out.groupSize);
  out.progressNotes = collectProgress(row);
  out.eventDateFlexibleBool = isFlexible(out.eventDateFlexible);
  out.eventDateDisplay = out.eventDateFlexibleBool ? 'Date TBC' : (out.fullEventDate || '');
  return out;
})
.filter((l) => l.referenceNumber || l.name || l.email) // drop blank / alwaysOutputData placeholder rows
.reverse(); // newest first

return [{ json: { count: leads.length, mode, leads } }];

const body = $input.first().json.body || $input.first().json;
return [{ json: {
  mode: body.mode === 'live' ? 'live' : 'demo',
  referenceNumber: body.referenceNumber || '',
  email: body.email || '',
  leadName: body.leadName || '',
  note: body.note || '',
  tag: body.tag || '',
  createdAt: new Date().toISOString(),
}}];

// Return raw rows per source tab. Source tabs are not clean tables
// (they carry title / notes rows), so no schema is invented here.
function rows(name) {
  let all = [];
  try { all = $(name).all().map((i) => i.json || {}); } catch (e) { all = []; }
  return all.filter((r) => Object.keys(r).length && Object.values(r).some((v) => String(v).trim() !== ''));
}
const vesselRates = rows('Price Comparison Read');
const cateringRates = rows('Cost Mother Read');
const quoteBuilder2026 = rows('QuoteBuilder Tab');
const margins = rows('Minimum Margin Read');
const staffRatios = rows('Ratios');
const cutleryRatios = rows('cutlery Ratios');
return [{ json: {
  ok: true,
  source: 'live',
  note: 'Raw rows returned as-is; map defensively in the UI.',
  vesselRates,
  cateringRates,
  quoteBuilder2026,
  margins,
  staffRatios,
  cutleryRatios,
  counts: {
    vesselRates: vesselRates.length,
    cateringRates: cateringRates.length,
    quoteBuilder2026: quoteBuilder2026.length,
    margins: margins.length,
    staffRatios: staffRatios.length,
    cutleryRatios: cutleryRatios.length,
  },
}}];
